import os
import numpy as np

working_dir = os.path.join(os.getcwd(), "working")
experiment_data_path = os.path.join(working_dir, "experiment_data.npy")

experiment_data = np.load(experiment_data_path, allow_pickle=True).item()


def safe_float(x):
    try:
        return float(x)
    except Exception:
        return x


def print_train_val_metrics(dataset_name, dataset_payload):
    metrics = dataset_payload.get("metrics", {})
    losses = dataset_payload.get("losses", {})

    train_metrics = metrics.get("train", [])
    val_metrics = metrics.get("val", [])
    train_losses = losses.get("train", [])
    val_losses = losses.get("val", [])

    print(f"Dataset: {dataset_name}")

    if train_metrics:
        final_train_acc = safe_float(train_metrics[-1].get("acc"))
        best_train_acc = safe_float(
            max(m.get("acc") for m in train_metrics if "acc" in m)
        )
        print(f"Final train accuracy: {final_train_acc:.6f}")
        print(f"Best train accuracy: {best_train_acc:.6f}")

    if val_metrics:
        final_val_acc = safe_float(val_metrics[-1].get("acc"))
        best_val_acc = safe_float(max(m.get("acc") for m in val_metrics if "acc" in m))
        print(f"Final validation accuracy: {final_val_acc:.6f}")
        print(f"Best validation accuracy: {best_val_acc:.6f}")

    if train_losses:
        final_train_loss = safe_float(train_losses[-1].get("loss"))
        best_train_loss = safe_float(
            min(m.get("loss") for m in train_losses if "loss" in m)
        )
        print(f"Final train loss: {final_train_loss:.6f}")
        print(f"Best train loss: {best_train_loss:.6f}")

    if val_losses:
        final_val_loss = safe_float(val_losses[-1].get("loss"))
        best_val_loss = safe_float(
            min(m.get("loss") for m in val_losses if "loss" in m)
        )
        print(f"Final validation loss: {final_val_loss:.6f}")
        print(f"Best validation loss: {best_val_loss:.6f}")


def print_stream_metrics(dataset_name, dataset_payload):
    stream_metrics_list = dataset_payload.get("metrics", {}).get("stream", [])
    if not stream_metrics_list:
        return

    latest_stream_metrics = stream_metrics_list[-1]

    for key, value in latest_stream_metrics.items():
        if key == "epoch":
            continue

        readable_name = key.replace("_", " ")
        readable_name = readable_name.replace("/", " ")
        print(
            f"{readable_name}: {safe_float(value):.6f}"
            if isinstance(value, (int, float, np.floating))
            else f"{readable_name}: {value}"
        )


for dataset_name, dataset_payload in experiment_data.items():
    print_train_val_metrics(dataset_name, dataset_payload)
    print_stream_metrics(dataset_name, dataset_payload)
    print()
